#include <stdio.h>
#include <limits.h>
#include <math.h>

int min(int a, int b) {
    return a < b ? a : b;
}

int dist(int a[], int b[]) {
    return abs(a[0] - b[0]) + abs(a[1] - b[1]);
}

void solve() {
    int n;
    scanf("%d", &n);
    int points[2 * n + 1][2];
    for (int i = 0; i < 2 * n; i++) {
        scanf("%d %d", &points[i][0], &points[i][1]);
    }
    points[2 * n][0] = 0;
    points[2 * n][1] = 0;

    int dis[2 * n + 1][2 * n + 1];
    for (int i = 0; i <= 2 * n; i++) {
        for (int j = i + 1; j <= 2 * n; j++) {
            dis[i][j] = dis[j][i] = dist(points[i], points[j]);
        }
    }

    int dp[1 << (2 * n)][2 * n + 1];
    for (int mask = 0; mask < (1 << (2 * n)); mask++) {
        for (int i = 0; i <= 2 * n; i++) {
            dp[mask][i] = INT_MAX;
        }
    }

    dp[0][2 * n] = 0;
    for (int mask = 0; mask < (1 << (2 * n)); mask++) {
        for (int i = 0; i <= 2 * n; i++) {
            if (dp[mask][i] == INT_MAX) continue;
            for (int j = 0; j < 2 * n; j++) {
                if ((mask & (1 << j)) != 0) continue;
                int new_mask = mask | (1 << j);
                dp[new_mask][j] = min(dp[new_mask][j], dp[mask][i] + dis[i][j]);
            }
        }
    }

    int ans = INT_MAX;
    for (int i = 0; i <= 2 * n; i++) {
        ans = min(ans, dp[(1 << (2 * n)) - 1][i] + dis[i][2 * n]);
    }
    printf("%d\n", ans);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) solve();
    return 0;
}

