        int[][] points = new int[NN + 1][2];
        for (int i = 0; i < NN; i++) {
            points[i][0] = sc.nextInt();
            points[i][1] = sc.nextInt();
        }
        points[NN][0] = 0;
        points[NN][1] = 0;

        int[][] dis = new int[NN + 1][NN + 1];
        for (int i = 0; i <= NN; i++) {
            for (int j = i + 1; j <= NN; j++) {
                dis[i][j] = dis[j][i] = Math.abs(points[i][0] - points[j][0]) + Math.abs(points[i][1] - points[j][1]);
            }
        }

        int[][] dp = new int[1 << (NN)][NN + 1];
        for (int mask = 0; mask < (1 << (NN)); mask++) {
            for (int i = 0; i <= NN; i++) {
                dp[mask][i] = INF;
            }
        }

        dp[0][NN] = 0;
        for (int mask = 0; mask < (1 << (NN)); mask++) {
            for (int i = 0; i <= NN; i++) {
                if (dp[mask][i] == INF) continue;
                for (int j = 0; j < NN; j++) {
                    if ((mask & (1 << j)) != 0) continue;
                    int new_mask = mask | (1 << j);
                    dp[new_mask][j] = Math.min(dp[new_mask][j], dp[mask][i] + dis[i][j]);
                }
            }
        }

        int ans = INF;
        for (int i = 0; i <= NN; i++) {
            ans = Math.min(ans, dp[(1 << (NN)) - 1][i] + dis[i][NN]);
        }
        pw.println(ans);
    }
    static FastScanner sc = new FastScanner(System.in);
    static PrintWriter pw = new PrintWriter(System.out);
    public static void main(String[] args) throws Exception {
        int t = sc.nextInt();
        while (t-- > 0) {
            solve();
        }
        pw.close();
    }
    static class FastScanner {
        BufferedReader br;
        StringTokenizer st;
        public FastScanner(InputStream is) {
            br = new BufferedReader(new InputStreamReader(is));
        }
        String next() throws IOException {
            while (st == null || !st.hasMoreTokens()) {
                st = new StringTokenizer(br.readLine());
            }
            return st.nextToken();
        }
        int nextInt() throws IOException {
            return Integer.parseInt(next());
        }
    }
}

