        points.append(list(map(int, input().split())))

    dis = [[0] * (2 * n + 1) for _ in range(2 * n + 1)]
    for i in range(2 * n + 1):
        for j in range(i + 1, 2 * n + 1):
            dis[i][j] = dis[j][i] = dist(points[i], points[j])

    dp = [[float('inf')] * (2 * n + 1) for _ in range(1 << (2 * n))]
    dp[0][2 * n] = 0
    for mask in range(1 << (2 * n)):
        for i in range(2 * n + 1):
            if dp[mask][i] == float('inf'):
                continue
            for j in range(2 * n):
                if (mask & (1 << j)):
                    continue
                new_mask = mask | (1 << j)
                dp[new_mask][j] = min(dp[new_mask][j], dp[mask][i] + dis[i][j])

    ans = float('inf')
    for i in range(2 * n + 1):
        ans = min(ans, dp[(1 << (2 * n)) - 1][i] + dis[i][2 * n])
